    public RekenChainFactoryImp(Admin admin, NlpGlobalService globalService) {
        this.constantManager = new ConstantManagerImp(admin, globalService.getConstantService());
        this.globalService = globalService;
    }


    @Override
    public Chain getRekenChain(RekenChainType type, RkmTijdperk tijdperk) {
        Chain rekenchain;
        switch (type) {
            case NORMAAL:
                rekenchain = new RekenMainChain(constantManager, globalService, tijdperk);
                break;
            case ACHTERSTAL:
                rekenchain = new RekenAchterstalChain(constantManager, globalService, tijdperk);
                break;
            case APO:
                rekenchain = new AchterstalPreOmschakelingChain(constantManager, globalService);
                break;
            case VOORSCHOT:
                rekenchain = new VoorschotChain(constantManager, globalService);
                break;
            default:
                throw new MessageException("Onbekend type RekenChain");
        }

        return rekenchain;
    }

    public Command getBerekenSocialeBijdragen(RkmTijdperk tijdperk) {
        switch (tijdperk) {
            case RSZPPO:
                return getCommandRszppo();
            case DMFAPPL:
                return getCommandDmfappl();
            case DMFA:
                return getCommandDmfa();
            default:
                throw new MessageException("Onbekend tijdperk");
        }
    }

    protected Command getCommandRszppo() {
        return new BerekenSocialeBijdragenRszppo(constantManager, globalService);
    }

    protected Command getCommandDmfappl() {
        Chain dmfapplChain = new ChainBase();
        dmfapplChain.addCommand(new BerekenSocialeBijdragenDmfappl(constantManager, globalService));
        dmfapplChain.addCommand(new BerekenPens2Antwerpen(constantManager, globalService));
        return dmfapplChain;
    }

    protected Command getCommandDmfa() {
        Chain dmfaChain = new ChainBase();
        dmfaChain.addCommand(new BerekenSocialeBijdragenDmfa(constantManager, globalService));
        return dmfaChain;
    }

    protected Command getManueleTussenkomstCommand(RekenFase rekenFase, Set<MoneyKey>... bedragTypes) {
        ImmutableSet.Builder<MoneyKey> builder = ImmutableSet.builder();
        for (Set<MoneyKey> bedragTypesSet : bedragTypes) {
            builder.addAll(bedragTypesSet);
        }
        return getManueleTussenkomstCommand(builder.build(), rekenFase);
    }

    protected Command getManueleTussenkomstCommand(Set<MoneyKey> bedragTypes, RekenFase rekenFase) {
        return new DoeTussenkomst(bedragTypes);
