    public class RekenMainChain extends ChainBase {

        public RekenMainChain(ConstantManager constantManager, NlpGlobalService globalService, RkmTijdperk tijdperk) {
            addCommand(new BrutoChain(constantManager, globalService));
            addCommand(new RszChain(constantManager, globalService, tijdperk));
            addCommand(new BijzondereBijdrageChain(constantManager));
            addCommand(new TerugbetalingSocialeBijdragenCommand(constantManager));
            addCommand(new BelastbaarChain(constantManager, globalService));

            addCommand(new TheoretischJaarWeddeChain(constantManager, globalService));
            addCommand(new BedrijfsvoorheffingChain(constantManager, globalService));


            addCommand(new NettoEnInhoudingenChain(constantManager, globalService));
            addCommand(new TailChain(false));
        }
    }

